import{_ as i,o as t,c as a,ag as r}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"Vehicle-Specific Setup (ArduPilot)","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/setup_view/ardupilot/vehicle_specific.md","filePath":"tr/qgc-user-guide/setup_view/ardupilot/vehicle_specific.md"}'),o={name:"tr/qgc-user-guide/setup_view/ardupilot/vehicle_specific.md"};function l(c,e,s,n,d,u){return t(),a("div",null,e[0]||(e[0]=[r('<h1 id="vehicle-specific-setup-ardupilot" tabindex="-1">Vehicle-Specific Setup (ArduPilot) <a class="header-anchor" href="#vehicle-specific-setup-ardupilot" aria-label="Permalink to &quot;Vehicle-Specific Setup (ArduPilot)&quot;">​</a></h1><p>Some ArduPilot vehicle types display additional configuration pages that are only relevant to that vehicle class.</p><h2 id="helicopter" tabindex="-1">Helicopter <a class="header-anchor" href="#helicopter" aria-label="Permalink to &quot;Helicopter&quot;">​</a></h2><p>Available on traditional helicopter frames (ArduPilot 4.0+):</p><ul><li><strong>Swashplate</strong> — servo manual mode, swashplate type, collective direction, linearize servo, flybar mode, cyclic max, collective min/max/angles, zero-thrust collective, landing collective minimum</li><li><strong>Rotor Speed Control (RSC)</strong> — RSC mode, critical rotor speed, ramp/runup/cooldown times, setpoint, idle percentage, throttle curve (0/25/50/75/100%), governor settings (reference/range/RPM/torque/FF)</li></ul><h2 id="submarine" tabindex="-1">Submarine <a class="header-anchor" href="#submarine" aria-label="Permalink to &quot;Submarine&quot;">​</a></h2><p>Available on ArduSub frames (ArduPilot 3.5+):</p><ul><li><strong>Sub Frame</strong> — select the submarine frame configuration (BlueROV1, BlueROV2/Vectored, Vectored-6DOF, etc.) with a visual frame selector. Option to load vehicle default parameters after selection.</li><li><strong>Lights</strong> — configure light output channel assignments (<code>SERVOn_FUNCTION</code>), step size (<code>JS_LIGHTS_STEP</code>), and number of brightness steps (<code>JS_LIGHTS_STEPS</code>)</li></ul><h2 id="fixed-wing" tabindex="-1">Fixed Wing <a class="header-anchor" href="#fixed-wing" aria-label="Permalink to &quot;Fixed Wing&quot;">​</a></h2><p>Fixed-wing vehicles may show additional pages for airspeed sensor calibration when an airspeed sensor is detected.</p>',10)]))}const m=i(o,[["render",l]]);export{h as __pageData,m as default};
